template:
[[SLOT import_line]]

[[SLOT seal_kw]] class Shape {}

class Circle extends Shape {
  final double radius;
  Circle(this.radius);
}

class Rectangle extends Shape {
  final double width;
  final double height;
  Rectangle(this.width, this.height);
}

class Triangle extends Shape {
  final double base;
  final double height;
  Triangle(this.base, this.height);
}

double totalArea(List<Shape> shapes) {
  return shapes.fold([[SLOT fold_init]], (sum, shape) {
    return sum + switch (shape) {
      Circle(radius: var r) => pi * r * r,
      Rectangle(width: var w, height: var h) => w * h,
      Triangle(base: var b, height: var h) => [[SLOT triangle_area]],
    };
  });
}
